    "\u2022 \u05D4\u05DC\u05DC \u05DE\u05DC\u05D0 \u05D5\u05DE\u05D5\u05E1\u05E3; \u05E2\u05DE\u05D9\u05D3\u05D4 \u05E9\u05DC \u05D9\u05D5\u05DD \u05D8\u05D5\u05D1.\n\n"
