    "\u05D1\u05E9\u05DE\u05D9\u05E0\u05D9 \u05E2\u05E6\u05E8\u05EA (\u05D5\u05D1\u05D9\u05D5\u05DD \u05DB\u05D9\u05E4\u05D5\u05E8). "
    "\u05E7\u05D4\u05D9\u05DC\u05D5\u05EA \u05E1\u05E4\u05E8\u05D3 \u05E8\u05D1\u05D5\u05EA \u05DC\u05D0 \u05D0\u05D5\u05DE\u05E8\u05D5\u05EA \u05D9\u05D6\u05DB\u05D5\u05E8 "
    "\u05D1\u05D9\u05D5\u05DD \u05D6\u05D4, \u05D0\u05D5 \u05E0\u05D5\u05D4\u05D2\u05D5\u05EA \u05DE\u05E0\u05D4\u05D2\u05D9 \u05D6\u05D9\u05DB\u05E8\u05D5\u05DF \u05E9\u05D5\u05E0\u05D9\u05DD\n\n"
    "\u05E9\u05DE\u05D7\u05EA \u05EA\u05D5\u05E8\u05D4:\n"
    "\u2022 \u05D7\u05D5\u05D2\u05D2 \u05D0\u05EA \u05D4\u05E9\u05DC\u05DE\u05EA \u05DE\u05D7\u05D6\u05D5\u05E8 \u05D4\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D4\u05E9\u05E0\u05EA\u05D9 "
